mapper.select:
SELECT p.id, p.category, p.title, p.view_count, p.like_count, p.comment_count, p.is_pinned, p.user_id AS author_id, u.name AS author_name, p.created_at FROM community_posts p JOIN users u ON u.id = p.user_id AND u.deleted_at IS NULL WHERE p.deleted_at IS NULL
AND p.category = #{category}
ORDER BY p.is_pinned DESC, p.created_at DESC LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE community_posts
SET    deleted_at = NOW(), updated_at = NOW()
WHERE  id         = #{id}
  AND  user_id    = #{userId}
  AND  deleted_at IS NULL

UPDATE community_comments
SET    deleted_at = NOW(), updated_at = NOW()
WHERE  id         = #{id}
  AND  user_id    = #{userId}
  AND  deleted_at IS NULL

mapper.delete:
DELETE FROM community_likes
WHERE  post_id = #{postId}
  AND  user_id = #{userId}

mapper.update:
UPDATE community_posts
SET    like_count = (
           SELECT COUNT(*) FROM community_likes WHERE post_id = #{postId}
       ),
       updated_at = NOW()
WHERE  id         = #{postId}
